INSERT INTO exercise_categories (name) VALUES
  ('Warm-Up'),
  ('Upper Mobility'),
  ('Lower Mobility'),
  ('Full Body')
INSERT INTO exercises (name, instructions, muscle_groups, category_id, is_public) VALUES
  ('Air Squats', 'Bodyweight squat used as a warm-up movement. Focus on full range of motion and controlled tempo.', '{Quads,Glutes}', (SELECT id FROM exercise_categories WHERE name = 'Warm-Up'), true),
  ('Arm Circles - Forward', 'Stand tall and make large forward circles with both arms. Great for warming up the shoulder joint.', '{Shoulders}', (SELECT id FROM exercise_categories WHERE name = 'Warm-Up'), true),
  ('Arm Circles - Backward', 'Stand tall and make large backward circles with both arms. Great for warming up the shoulder joint.', '{Shoulders}', (SELECT id FROM exercise_categories WHERE name = 'Warm-Up'), true),
  ('Leg Swings - Front to Back', 'Hold a wall for support and swing one leg forward and backward in a controlled arc.', '{Hamstrings,Quads}', (SELECT id FROM exercise_categories WHERE name = 'Warm-Up'), true),
  ('Leg Swings - Lateral', 'Hold a wall for support and swing one leg side to side in a controlled arc.', '{Glutes}', (SELECT id FROM exercise_categories WHERE name = 'Warm-Up'), true),
  ('Hamstring Kicks', 'Walk forward kicking one leg straight up toward your extended hand. Alternate legs.', '{Hamstrings}', (SELECT id FROM exercise_categories WHERE name = 'Warm-Up'), true),
  ('Hamstring Scoops', 'Bend forward and scoop your hands under your foot as you lift it. Works hip flexor and hamstring mobility.', '{Hamstrings}', (SELECT id FROM exercise_categories WHERE name = 'Warm-Up'), true),
  ('Inchworms with Full Extension', 'Walk your hands out to a plank, pause, then fully extend your arms overhead before walking back up.', '{Hamstrings,Shoulders,Rectus Abdominis}', (SELECT id FROM exercise_categories WHERE name = 'Warm-Up'), true),
  ('Gate Swings', 'From a squat position, open one knee out wide like a gate swinging open, then close it. Alternate sides.', '{Glutes,Quads}', (SELECT id FROM exercise_categories WHERE name = 'Warm-Up'), true),
  ('Open the Gate', 'Lift one knee up and rotate it outward, stepping over an imaginary fence. Great hip mobility warm-up.', '{Glutes}', (SELECT id FROM exercise_categories WHERE name = 'Warm-Up'), true),
  ('Close the Gate', 'Lift one knee up and rotate it inward, stepping over an imaginary fence in the opposite direction.', '{Glutes}', (SELECT id FROM exercise_categories WHERE name = 'Warm-Up'), true),
  ('Scorpions', 'Lie face down with arms out. Lift one foot and cross it over to the opposite side, rotating your hips. Hold briefly.', '{Lower Back}', (SELECT id FROM exercise_categories WHERE name = 'Warm-Up'), true),
  ('Fire Hydrant', 'Start in a quadruped position. Lift one knee out to the side like a dog at a fire hydrant. Keep your core stable.', '{Glutes}', (SELECT id FROM exercise_categories WHERE name = 'Warm-Up'), true),
  ('Quadruped Hip Circles - Forward', 'In a quadruped position, make large forward circles with one knee. Keep your core braced.', '{Glutes}', (SELECT id FROM exercise_categories WHERE name = 'Warm-Up'), true),
  ('Quadruped Hip Circles - Backward', 'In a quadruped position, make large backward circles with one knee. Keep your core braced.', '{Glutes}', (SELECT id FROM exercise_categories WHERE name = 'Warm-Up'), true),
  ('Quadruped Straight Leg Lifts', 'In a quadruped position, extend one leg straight back and lift it. Squeeze your glute at the top.', '{Glutes,Lower Back}', (SELECT id FROM exercise_categories WHERE name = 'Warm-Up'), true),
  ('Cobra Up Downs', 'Start lying face down. Press up through your hands into a cobra pose, then lower back down. Great for thoracic mobility.', '{Lower Back,Rectus Abdominis}', (SELECT id FROM exercise_categories WHERE name = 'Warm-Up'), true),
  ('Kneeling Sit Backs', 'Start in a quadruped position. Push your hips back toward your heels, stretching your lower back and hips.', '{Lower Back}', (SELECT id FROM exercise_categories WHERE name = 'Warm-Up'), true),
  ('Carioca', 'Move laterally crossing one foot in front of the other, then behind. Stay light on your feet and keep your hips rotating.', '{Full Body}', (SELECT id FROM exercise_categories WHERE name = 'Warm-Up'), true),
  ('Speed Skips', 'Skip forward driving your knee up high with each stride. Focus on height and arm drive.', '{Calves,Quads}', (SELECT id FROM exercise_categories WHERE name = 'Warm-Up'), true),
  ('Speed Skips for Height', 'Skip forward focusing on getting as much height as possible with each skip. Maximize arm drive.', '{Calves,Quads}', (SELECT id FROM exercise_categories WHERE name = 'Warm-Up'), true),
  ('Walk Figure 4', 'Walk forward and with each step bring one ankle across your opposite knee in a figure 4 stretch as you hinge forward.', '{Glutes}', (SELECT id FROM exercise_categories WHERE name = 'Warm-Up'), true),
  ('Side Shuffle', 'Move laterally in an athletic stance, pushing off the trailing foot. Stay low and keep your chest up.', '{Quads,Glutes}', (SELECT id FROM exercise_categories WHERE name = 'Warm-Up'), true),
  ('Backpedal', 'Run backward staying low in an athletic stance. Look over your shoulder for direction.', '{Quads,Glutes}', (SELECT id FROM exercise_categories WHERE name = 'Warm-Up'), true),
  ('Jumping Jacks', 'Jump feet out wide while raising arms overhead, then jump back to start. Classic full-body warm-up.', '{Full Body}', (SELECT id FROM exercise_categories WHERE name = 'Warm-Up'), true),
  ('Marching', 'Walk in place lifting your knees to hip height. Pump arms opposite to legs.', '{Quads}', (SELECT id FROM exercise_categories WHERE name = 'Warm-Up'), true),
  ('Slow Jog', 'Easy-paced jog to elevate heart rate and warm up joints before more intense activity.', '{Full Body}', (SELECT id FROM exercise_categories WHERE name = 'Warm-Up'), true),
  ('Half Kneeling Thoracic Elbow to Knee', 'In a half kneeling position, place your hand behind your head and rotate your elbow down toward your front knee. Great thoracic rotation stretch.', '{Lower Back}', (SELECT id FROM exercise_categories WHERE name = 'Warm-Up'), true),
  ('Supine Double Knee Lumbar Twist', 'Lie on your back with knees bent. Drop both knees to one side while keeping shoulders flat. Hold, then switch.', '{Lower Back}', (SELECT id FROM exercise_categories WHERE name = 'Warm-Up'), true),
  ('Cat Cow', 'On hands and knees, alternate between arching your back toward the ceiling (cat) and dropping it toward the floor (cow). Move slowly and breathe.', '{Lower Back}', (SELECT id FROM exercise_categories WHERE name = 'Lower Mobility'), true),
  ('Downward Dog to Cobra', 'From downward dog, shift forward into a high plank then lower your hips and lift your chest into cobra. Flow between the two.', '{Lower Back,Shoulders}', (SELECT id FROM exercise_categories WHERE name = 'Lower Mobility'), true),
  ('Pigeon Stretch', 'From a lunge position, bring your front shin across the mat and sink your hips toward the ground. Great hip opener.', '{Glutes}', (SELECT id FROM exercise_categories WHERE name = 'Lower Mobility'), true),
  ('Thread the Needle', 'In a quadruped position, slide one arm underneath you, rotating your thoracic spine. Hold at the end range.', '{Lower Back}', (SELECT id FROM exercise_categories WHERE name = 'Upper Mobility'), true),
  ('90/90 Hip Stretch', 'Sit with both legs bent at 90 degrees — one in front, one to the side. Sit tall and work on rotating between positions to improve hip mobility.', '{Glutes}', (SELECT id FROM exercise_categories WHERE name = 'Lower Mobility'), true),
  ('Thoracic Spine Rotations', 'In a quadruped position, place one hand behind your head and rotate your elbow toward the ceiling. Follow with your eyes.', '{Lower Back}', (SELECT id FROM exercise_categories WHERE name = 'Upper Mobility'), true),
  ('Kneeling Hip Flexor Stretch', 'From a half kneeling position, push your hips forward to stretch the hip flexor of the back leg. Keep your core braced.', '{Quads}', (SELECT id FROM exercise_categories WHERE name = 'Lower Mobility'), true),
  ('Ankle Circles - ABCs', 'Trace the letters of the alphabet with your toe. Great for ankle mobility and proprioception.', '{Calves}', (SELECT id FROM exercise_categories WHERE name = 'Lower Mobility'), true),
  ('Dorsiflexion Wall Mobilization', 'Stand facing a wall and drive your knee forward over your toe repeatedly. Excellent for improving ankle dorsiflexion.', '{Calves}', (SELECT id FROM exercise_categories WHERE name = 'Lower Mobility'), true),
  ('World''s Greatest Stretch', 'From a lunge position, place the same-side hand on the floor, then reach the opposite arm up to the ceiling. A full-body mobility sequence.', '{Full Body}', (SELECT id FROM exercise_categories WHERE name = 'Lower Mobility'), true),
  ('Hip 90/90 Rotation', 'Sitting in a 90/90 position, rotate forward onto the front hip and then back to the rear hip. Move slowly through full range.', '{Glutes}', (SELECT id FROM exercise_categories WHERE name = 'Lower Mobility'), true),
  ('Frog Stretch with Leg Lift', 'Start in a wide squat. Drop your elbows to the floor then alternate lifting each leg straight out to the side.', '{Glutes}', (SELECT id FROM exercise_categories WHERE name = 'Lower Mobility'), true),
  ('Seated Knee to Chest', 'Sitting on the floor, bring one knee up and hug it to your chest. Hold to stretch your hip flexor and glute.', '{Glutes}', (SELECT id FROM exercise_categories WHERE name = 'Lower Mobility'), true),
  ('Divebomber Pushup', 'From downward dog, sweep your chest close to the floor forward into an upward dog position. Flow back to start.', '{Shoulders,Lower Back}', (SELECT id FROM exercise_categories WHERE name = 'Upper Mobility'), true),
  ('Wall Angles', 'Stand with your back against a wall. Try to slide your arms up and down the wall while keeping your back flat. Great for shoulder mobility.', '{Shoulders}', (SELECT id FROM exercise_categories WHERE name = 'Upper Mobility'), true),
  ('Open Books', 'Lie on your side with knees bent. Reach your top arm back to open your chest toward the ceiling. Hold and return.', '{Lower Back}', (SELECT id FROM exercise_categories WHERE name = 'Upper Mobility'), true),
  ('Foam Roller Mid Back', 'Place a foam roller under your mid back. Support your head and gently extend over the roller. Move up and down to mobilize thoracic spine.', '{Lower Back}', (SELECT id FROM exercise_categories WHERE name = 'Upper Mobility'), true),
  ('Thoracic Extension', 'Sit in a chair or kneel and place hands behind your head. Gently extend your upper back over your hands. Work thoracic mobility.', '{Lower Back}', (SELECT id FROM exercise_categories WHERE name = 'Upper Mobility'), true),
  ('Sleeper Stretch', 'Lie on your side with your arm at 90 degrees. Use the other hand to gently push your wrist toward the floor. Stretches posterior shoulder capsule.', '{Shoulders}', (SELECT id FROM exercise_categories WHERE name = 'Upper Mobility'), true),
  ('Lateral Walk Hip Opener', 'Step sideways and with each step drop into a brief side lunge to open the hip. Stay low and controlled.', '{Glutes,Quads}', (SELECT id FROM exercise_categories WHERE name = 'Lower Mobility'), true),
  ('Nordic Curls', 'Kneel on a pad with your feet anchored. Slowly lower your body toward the floor by extending your knees, catching yourself with your hands. Pull back up using your hamstrings. One of the best hamstring exercises.', '{Hamstrings}', (SELECT id FROM exercise_categories WHERE name = 'Legs'), true),
  ('Reverse Nordic Curls', 'Kneel on a pad with your feet anchored. Lean back slowly, keeping your body straight from knee to head. Catch yourself before falling. Use your quads throughout.', '{Quads}', (SELECT id FROM exercise_categories WHERE name = 'Legs'), true),
  ('Cossack Squat', 'Stand with feet wide and toes angled out. Shift your weight to one side, squatting deep on that leg while extending the other straight. Alternate sides.', '{Quads,Glutes,Hamstrings}', (SELECT id FROM exercise_categories WHERE name = 'Legs'), true),
  ('Box Squat', 'Set up with a box behind you. Sit back onto the box under control, then drive through your heels to stand. Teaches proper hip hinge in the squat.', '{Quads,Glutes,Hamstrings}', (SELECT id FROM exercise_categories WHERE name = 'Legs'), true),
  ('Hack Squat', 'Place the barbell behind your legs or use a hack squat machine. Squat deeply keeping the bar close to your body. Targets quads heavily.', '{Quads,Glutes}', (SELECT id FROM exercise_categories WHERE name = 'Legs'), true),
  ('Barbell Hip Thrust - Single Leg', 'Set up like a regular hip thrust but with one leg extended. Drive through the planted heel to lift your hips. Isolates each glute.', '{Glutes,Hamstrings}', (SELECT id FROM exercise_categories WHERE name = 'Legs'), true),
  ('Sprinter Bridge', 'Start in a bridge position. Drive one knee up toward your chest while pressing through the opposite heel. Mimics the sprinting position.', '{Glutes,Hamstrings}', (SELECT id FROM exercise_categories WHERE name = 'Legs'), true),
  ('Kneeling Squat Jumps', 'Start kneeling on a pad. Explosively swing your arms and land in a squat position. Develops power from the hips.', '{Glutes,Quads}', (SELECT id FROM exercise_categories WHERE name = 'Legs'), true),
  ('Kneeling Squats', 'Kneel on a pad with feet hip width apart. Lower your glutes toward your heels then return to upright kneeling. Add weight as needed.', '{Glutes,Quads}', (SELECT id FROM exercise_categories WHERE name = 'Legs'), true),
  ('Fire Hydrants', 'Start in a quadruped position. Lift one knee out to the side keeping the knee bent at 90 degrees. Focus on glute activation.', '{Glutes}', (SELECT id FROM exercise_categories WHERE name = 'Legs'), true),
  ('Wall Bridge', 'Lie on your back with feet on the wall. Drive through your heels to lift your hips. Keep your core tight throughout.', '{Glutes,Hamstrings}', (SELECT id FROM exercise_categories WHERE name = 'Legs'), true),
  ('3 Way Calf Raise', 'Perform calf raises with toes straight, toes in, and toes out — one set in each position. Hits all three heads of the calf.', '{Calves}', (SELECT id FROM exercise_categories WHERE name = 'Legs'), true),
  ('Toe Walks', 'Walk forward on the balls of your feet with heels raised off the ground. Stay tall and controlled. Builds calf strength and ankle stability.', '{Calves}', (SELECT id FROM exercise_categories WHERE name = 'Legs'), true),
  ('Bridge with Calf Raise', 'Hold a bridge position. Lift your heels off the floor into a calf raise while keeping your hips up. Combination glute and calf exercise.', '{Glutes,Calves}', (SELECT id FROM exercise_categories WHERE name = 'Legs'), true),
  ('Sumo Deadlift', 'Take a very wide stance with toes pointed out significantly. Grip the bar inside your legs and pull. Targets inner thighs and glutes more than conventional.', '{Glutes,Hamstrings,Quads}', (SELECT id FROM exercise_categories WHERE name = 'Legs'), true),
  ('Lateral Broad Jump', 'Jump as far as possible to the side, landing softly on both feet. Reload and jump back. Develops lateral power.', '{Quads,Glutes,Calves}', (SELECT id FROM exercise_categories WHERE name = 'Legs'), true),
  ('Countermovement Jump', 'Stand tall, quickly drop into a partial squat and immediately explode upward. The pre-stretch maximizes jump height.', '{Quads,Glutes,Calves}', (SELECT id FROM exercise_categories WHERE name = 'Legs'), true),
  ('Transverse Step Up', 'Step up onto a box that is oriented to the side. Rotate your body as you step to challenge hip stability in all planes.', '{Quads,Glutes}', (SELECT id FROM exercise_categories WHERE name = 'Legs'), true),
  ('Elevator Squats', 'Perform a squat and hold at three different depths — about a quarter, halfway, and full squat — pausing briefly at each level.', '{Quads,Glutes}', (SELECT id FROM exercise_categories WHERE name = 'Legs'), true),
  ('Spanish Squats', 'Loop a band around a post and step back, placing the band behind your knees. Squat keeping your shins vertical. Excellent for knee rehab and VMO activation.', '{Quads}', (SELECT id FROM exercise_categories WHERE name = 'Legs'), true),
  ('Skater Squats', 'Balance on one leg. Lower the opposite knee toward the floor in a single leg squat. Keep your chest up and knee aligned.', '{Quads,Glutes}', (SELECT id FROM exercise_categories WHERE name = 'Legs'), true),
  ('Glute Bridge March', 'Hold a bridge position and alternate lifting each foot off the ground in a marching motion. Keep your hips level throughout.', '{Glutes,Rectus Abdominis}', (SELECT id FROM exercise_categories WHERE name = 'Legs'), true),
  ('Hip Thrust', 'Sit with your upper back against a bench, barbell across your hips. Drive through your heels and squeeze your glutes at the top.', '{Glutes,Hamstrings}', (SELECT id FROM exercise_categories WHERE name = 'Legs'), true),
  ('Cable Pull Through', 'Stand facing away from a cable machine. Reach through your legs to grab the rope and hinge forward. Drive your hips forward to stand. Great glute exercise.', '{Glutes,Hamstrings}', (SELECT id FROM exercise_categories WHERE name = 'Legs'), true),
  ('Banded Glute Bridge', 'Perform a bridge with a resistance band just above your knees. Push knees out against the band throughout. Activates glutes and hip abductors.', '{Glutes,Hamstrings}', (SELECT id FROM exercise_categories WHERE name = 'Legs'), true),
  ('Banded Deadlift', 'Perform a deadlift with resistance bands anchored under your feet. The band adds tension at the top of the lift where you are strongest.', '{Hamstrings,Glutes,Lower Back}', (SELECT id FROM exercise_categories WHERE name = 'Legs'), true),
  ('Rack Pull', 'Set pins in a power rack above the knees. Pull the bar from this elevated position. Less range of motion, allows heavier loads.', '{Hamstrings,Lower Back,Traps}', (SELECT id FROM exercise_categories WHERE name = 'Legs'), true),
  ('Sled Push', 'Push a weighted sled across a surface with straight arms or bent arms. Drives quad, glute, and calf development. Great for conditioning.', '{Quads,Glutes,Calves}', (SELECT id FROM exercise_categories WHERE name = 'Legs'), true),
  ('Sled Pull', 'Attach a harness or rope to a weighted sled and pull it toward you while walking backward. Works the posterior chain and grip.', '{Hamstrings,Glutes,Back}', (SELECT id FROM exercise_categories WHERE name = 'Legs'), true),
  ('Deadlift', 'With feet hip-width apart, push your hips back, grip the bar, and drive your feet into the floor to stand. Keep the bar close to your body throughout.', '{Hamstrings,Glutes,Lower Back,Traps}', (SELECT id FROM exercise_categories WHERE name = 'Legs'), true),
  ('Barbell Back Squat', 'Place the barbell across your upper traps. Brace your core, break at the hips and knees simultaneously, and squat to parallel or below. Drive through your heels to stand.', '{Quads,Glutes,Hamstrings}', (SELECT id FROM exercise_categories WHERE name = 'Legs'), true),
  ('Hip Abduction - Cable Machine', 'Attach a cable to your ankle and abduct your leg out to the side. Keep a slight bend in the standing knee. Targets outer glute.', '{Glutes}', (SELECT id FROM exercise_categories WHERE name = 'Legs'), true),
  ('Clam Shells - Seated', 'Sit in a chair with a band around your knees. Open and close your knees against the band. Activates hip abductors in a seated position.', '{Glutes}', (SELECT id FROM exercise_categories WHERE name = 'Legs'), true),
  ('Reverse Clam Shell', 'Lie on your side with hips at 90 degrees. Keep your feet together and rotate the top knee downward toward the floor. Works hip internal rotators.', '{Glutes}', (SELECT id FROM exercise_categories WHERE name = 'Legs'), true),
  ('Lunge Hold with Calf Raise', 'Get into a lunge position and hold. Perform calf raises on the front foot. Challenges balance and calf strength simultaneously.', '{Quads,Glutes,Calves}', (SELECT id FROM exercise_categories WHERE name = 'Legs'), true),
  ('Reverse Lunge - Airborne', 'Perform a reverse lunge and drive the back knee forward as you stand, jumping off the front foot. Land softly and immediately go into the next rep.', '{Quads,Glutes}', (SELECT id FROM exercise_categories WHERE name = 'Legs'), true),
  ('Arnold Press', 'Start with dumbbells at shoulder height, palms facing you. As you press overhead, rotate so palms face away at the top. Reverse on the way down.', '{Shoulders,Triceps}', (SELECT id FROM exercise_categories WHERE name = 'Arms'), true),
  ('Around the World', 'Hold a weight plate or dumbbell and make a large circle around your head. Stay controlled. Challenges shoulder stability and strength.', '{Shoulders}', (SELECT id FROM exercise_categories WHERE name = 'Arms'), true),
  ('Cable Face Pull', 'Attach a rope to a high cable. Pull the rope toward your face, spreading the ends apart at your ears. Excellent for rear delts and external rotation.', '{Shoulders,Traps}', (SELECT id FROM exercise_categories WHERE name = 'Arms'), true),
  ('Front Raises', 'Hold dumbbells at your sides and raise them straight in front of you to shoulder height. Lower slowly. Targets anterior deltoid.', '{Shoulders}', (SELECT id FROM exercise_categories WHERE name = 'Arms'), true),
  ('Rear Delt Fly', 'Bend over at the hips with a flat back. Raise both dumbbells out to the sides with a slight bend in the elbows. Squeezes the rear delts.', '{Shoulders,Back}', (SELECT id FROM exercise_categories WHERE name = 'Arms'), true),
  ('Dumbbell Pullover', 'Lie on a bench and hold a dumbbell overhead. Lower it back behind your head with straight arms, then pull back over. Targets lats and chest.', '{Lats,Chest}', (SELECT id FROM exercise_categories WHERE name = 'Arms'), true),
  ('Hammer Curls', 'Hold dumbbells with a neutral grip (palms facing each other). Curl to the top without rotating your wrist. Targets the brachialis and brachioradialis.', '{Biceps}', (SELECT id FROM exercise_categories WHERE name = 'Arms'), true),
  ('Preacher Curl', 'Use a preacher bench to lock your upper arms in place. Curl the weight up with full range of motion. Excellent for bicep isolation.', '{Biceps}', (SELECT id FROM exercise_categories WHERE name = 'Arms'), true),
  ('Concentration Curl', 'Sit on a bench and brace your elbow against your inner thigh. Curl the dumbbell straight up to your shoulder. Maximizes bicep contraction.', '{Biceps}', (SELECT id FROM exercise_categories WHERE name = 'Arms'), true),
  ('Zottman Curl', 'Curl up with a supinated grip, then rotate to a pronated grip at the top and lower slowly. Works both sides of the bicep.', '{Biceps}', (SELECT id FROM exercise_categories WHERE name = 'Arms'), true),
  ('Close Grip Bench Press', 'Grip the bar with hands shoulder-width apart. Lower to your chest and press back up. Emphasizes triceps over chest.', '{Triceps,Chest}', (SELECT id FROM exercise_categories WHERE name = 'Arms'), true),
  ('JM Press', 'A hybrid between a skullcrusher and a close-grip bench press. The bar travels to the upper chest/throat, loading the triceps heavily.', '{Triceps}', (SELECT id FROM exercise_categories WHERE name = 'Arms'), true),
  ('Tate Press', 'Lie on a bench with dumbbells pointing up. Flare your elbows out and lower the dumbbells toward your chest. Drive back up using your triceps.', '{Triceps}', (SELECT id FROM exercise_categories WHERE name = 'Arms'), true),
  ('Cable Tricep Extension', 'Attach a rope or bar to a high cable. Press down extending your arms fully. Keep your elbows at your sides throughout.', '{Triceps}', (SELECT id FROM exercise_categories WHERE name = 'Arms'), true),
  ('Wrist Curls', 'Sit with forearms on your thighs, palms up. Curl your wrists upward against a dumbbell or barbell. Targets wrist flexors.', '{Forearms}', (SELECT id FROM exercise_categories WHERE name = 'Arms'), true),
  ('Wrist Extensions', 'Sit with forearms on your thighs, palms down. Extend your wrists upward against a dumbbell or barbell. Targets wrist extensors.', '{Forearms}', (SELECT id FROM exercise_categories WHERE name = 'Arms'), true),
  ('Hammer Curl with Rotation', 'Perform a hammer curl and as you lower, rotate your palm outward. The rotation adds brachioradialis work.', '{Biceps,Forearms}', (SELECT id FROM exercise_categories WHERE name = 'Arms'), true),
  ('Band Pull Aparts', 'Hold a resistance band with both hands at shoulder width. Pull the band apart by squeezing your shoulder blades together. Great shoulder warm-up.', '{Shoulders,Back}', (SELECT id FROM exercise_categories WHERE name = 'Arms'), true),
  ('Dumbbell Cuban Rotations', 'Hold dumbbells with elbows bent at 90 degrees and upper arms parallel to the floor. Rotate forearms upward then extend overhead. Works external rotators.', '{Shoulders}', (SELECT id FROM exercise_categories WHERE name = 'Arms'), true),
  ('Javelin Press', 'Hold a barbell at one end in one hand and press it overhead. The offset load challenges shoulder stability.', '{Shoulders,Triceps}', (SELECT id FROM exercise_categories WHERE name = 'Arms'), true),
  ('Hang Clean', 'Start with the bar at mid-thigh. Explosively extend your hips and pull the bar up, rotating under it into a front rack position.', '{Quads,Hamstrings,Traps,Shoulders}', (SELECT id FROM exercise_categories WHERE name = 'Arms'), true),
  ('Push Press', 'Dip slightly at the knees and then drive the bar overhead using leg momentum. Heavier than a strict press.', '{Shoulders,Triceps,Quads}', (SELECT id FROM exercise_categories WHERE name = 'Arms'), true),
  ('Dumbbell A Press', 'Perform a chest press but angle the dumbbells inward so they form an A shape. Challenges the shoulder stabilizers differently.', '{Chest,Shoulders,Triceps}', (SELECT id FROM exercise_categories WHERE name = 'Arms'), true),
  ('Dumbbell Squeeze Press', 'Press two dumbbells together as hard as you can while performing a chest press. The squeeze increases pectoral activation.', '{Chest,Triceps}', (SELECT id FROM exercise_categories WHERE name = 'Arms'), true),
  ('Renegade Row', 'In a plank position holding two dumbbells, row one dumbbell to your hip while stabilizing with the other arm. Challenges core and back simultaneously.', '{Back,Rectus Abdominis,Biceps}', (SELECT id FROM exercise_categories WHERE name = 'Arms'), true),
  ('Man Makers', 'Hold two dumbbells and perform a pushup, then a renegade row on each side, then stand into a clean and press. Full body power movement.', '{Full Body,Chest,Back,Shoulders}', (SELECT id FROM exercise_categories WHERE name = 'Arms'), true),
  ('Svend Press', 'Stand holding a weight plate pressed between your palms at chest height. Press the plate forward by squeezing your hands together. Targets inner chest.', '{Chest}', (SELECT id FROM exercise_categories WHERE name = 'Arms'), true),
  ('Australian Pull-Ups', 'Set a bar at hip height. Grip the bar and hang underneath with your body straight. Pull your chest to the bar. A regression for full pull-ups.', '{Back,Biceps,Lats}', (SELECT id FROM exercise_categories WHERE name = 'Back & Neck'), true),
  ('Renegade Row', 'In a plank position holding two dumbbells, row one dumbbell to your hip while stabilizing with the other arm. Challenges core and back simultaneously.', '{Back,Rectus Abdominis,Biceps}', (SELECT id FROM exercise_categories WHERE name = 'Back & Neck'), true),
  ('Reverse Fly', 'Bend over at the hips with a flat back. Raise dumbbells out to the sides keeping a slight bend in the elbows. Targets rear delts and mid-back.', '{Back,Shoulders}', (SELECT id FROM exercise_categories WHERE name = 'Back & Neck'), true),
  ('Reverse Hyper', 'Lie face down on a bench with your legs hanging off. Lift your legs until they are parallel to the floor. Excellent for lower back and glutes.', '{Lower Back,Glutes}', (SELECT id FROM exercise_categories WHERE name = 'Back & Neck'), true),
  ('Scorpions', 'Lie face down with arms out. Lift one foot and cross it over to the opposite side, rotating your hips. Hold briefly. Great thoracic mobility exercise.', '{Lower Back}', (SELECT id FROM exercise_categories WHERE name = 'Back & Neck'), true),
  ('Pull-Up Hold', 'Get your chin over the bar and hold as long as possible. Great for building the strength needed for full pull-ups.', '{Lats,Back,Biceps}', (SELECT id FROM exercise_categories WHERE name = 'Back & Neck'), true),
  ('Chin-Up Hold', 'Hold a chin-up position with palms facing you and chin above the bar for as long as possible. Works the biceps and lats.', '{Biceps,Lats,Back}', (SELECT id FROM exercise_categories WHERE name = 'Back & Neck'), true),
  ('Seal Row', 'Lie face down on a raised bench with dumbbells hanging below. Row both dumbbells to your hips simultaneously. Eliminates lower body compensation.', '{Back,Lats,Biceps}', (SELECT id FROM exercise_categories WHERE name = 'Back & Neck'), true),
  ('GHD Extension', 'Use a GHD machine to perform back extensions through a full range of motion. Strengthens the posterior chain.', '{Lower Back,Glutes,Hamstrings}', (SELECT id FROM exercise_categories WHERE name = 'Back & Neck'), true),
  ('Neck Bridge', 'Balance on the top of your head and your feet with your body in a bridge position. Builds neck strength and stability. Use caution.', '{Neck}', (SELECT id FROM exercise_categories WHERE name = 'Back & Neck'), true),
  ('Modified Neck Bridge', 'Lie on your back and lift your hips into a bridge. Tilt your head back so the top touches the floor. A safer neck bridge progression.', '{Neck}', (SELECT id FROM exercise_categories WHERE name = 'Back & Neck'), true),
  ('Prone Neck Extensions', 'Lie face down with your head off the edge of a bench. Slowly raise your head against gravity. Strengthens neck extensors.', '{Neck}', (SELECT id FROM exercise_categories WHERE name = 'Back & Neck'), true),
  ('Pendlay Row', 'With the bar on the floor each rep, hinge over and explosively row the bar to your lower chest. Reset fully before each rep.', '{Back,Lats,Biceps}', (SELECT id FROM exercise_categories WHERE name = 'Back & Neck'), true),
  ('Barbell Row - Supinated Grip', 'Perform a bent over row with palms facing up. This supinated grip shifts more work to the biceps and lower lats.', '{Lats,Back,Biceps}', (SELECT id FROM exercise_categories WHERE name = 'Back & Neck'), true),
  ('Prone T Lumbar Raise', 'Lie face down with arms out in a T position. Lift your arms and chest off the floor. Targets the mid-back and rear delts.', '{Back,Shoulders}', (SELECT id FROM exercise_categories WHERE name = 'Back & Neck'), true),
  ('Prone Double Arm Swimmers', 'Lie face down. Alternate sweeping arms forward and back in a swimming motion while keeping arms and chest raised. Great for back endurance.', '{Back,Shoulders}', (SELECT id FROM exercise_categories WHERE name = 'Back & Neck'), true),
  ('Table Top Pull Overs', 'Lie under a bench in a bridge position. Grip the bench and pull yourself up into a row. Challenging back exercise.', '{Back,Lats}', (SELECT id FROM exercise_categories WHERE name = 'Back & Neck'), true),
